<script setup lang="ts">
/**
 * 角色选择/创建页
 *
 * 流程:
 * - 列出当前账号下的所有角色
 * - 创建新角色(校验 2~12 字符、中英文数字下划线)
 * - 选中角色 → 写 currentId + 拉详情 + 跳 redirect(默认 /)
 */

import { onMounted, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { storeToRefs } from 'pinia'
import { useCharacterStore } from '@/stores/character'
import { useUserStore } from '@/stores/user'

const router = useRouter()
const route = useRoute()
const char = useCharacterStore()
const user = useUserStore()
const { list, loading } = storeToRefs(char)

// ===== 创建角色 =====
const newNick = ref('')
const creating = ref(false)
const errorMsg = ref('')

async function handleCreate() {
  const nick = newNick.value.trim()
  if (nick.length < 2 || nick.length > 12) {
    errorMsg.value = '昵称需 2~12 字符'
    return
  }
  if (!/^[一-龥A-Za-z0-9_]+$/.test(nick)) {
    errorMsg.value = '昵称仅支持中英文 / 数字 / 下划线'
    return
  }
  creating.value = true
  errorMsg.value = ''
  try {
    await char.createOne({ nickname: nick })
    goRedirect()
  } catch (err: any) {
    errorMsg.value = err?.message ?? '创建失败'
  } finally {
    creating.value = false
  }
}

async function handleSelect(id: string) {
  await char.select(id)
  goRedirect()
}

function goRedirect() {
  const r = (route.query.redirect as string) || '/'
  router.replace(r)
}

function handleSignOut() {
  user.signOut()
  char.signOut()
  router.replace({ name: 'login' })
}

onMounted(() => {
  void char.fetchList()
})
</script>

<template>
  <div
    class="relative min-h-screen w-full flex flex-col items-center bg-slate-900 text-white overflow-hidden"
  >
    <!-- 顶栏:账号信息 + 登出 -->
    <header
      class="w-full max-w-5xl flex items-center justify-between px-4 py-3 text-[12px] text-amber-200/80"
    >
      <div class="flex items-center gap-2">
        <div
          class="w-7 h-7 rounded-full bg-gradient-to-br from-amber-500 to-rose-700 flex items-center justify-center text-sm ring-1 ring-amber-400"
        >
          🐧
        </div>
        <span class="font-bold">{{ user.user?.account ?? '游客' }}</span>
      </div>
      <button
        class="px-3 py-1 rounded bg-rose-700/80 hover:bg-rose-600 text-amber-100 text-[12px] border border-amber-500/40 transition active:scale-95"
        @click="handleSignOut"
      >
        登出
      </button>
    </header>

    <main class="flex-1 w-full max-w-5xl px-4 py-6 flex flex-col gap-6">
      <h1 class="text-2xl font-black tracking-widest text-amber-200 drop-shadow">选择角色</h1>

      <!-- 角色列表 -->
      <section>
        <h2 class="text-amber-200 text-[14px] font-bold mb-2">
          已有角色 <span class="text-amber-200/50">({{ list.length }})</span>
        </h2>
        <div v-if="loading && list.length === 0" class="text-amber-200/50 text-[12px] py-4">
          加载中…
        </div>
        <div
          v-else-if="list.length === 0"
          class="rounded-lg border border-amber-700/30 bg-black/30 p-6 text-center text-amber-200/60 text-[13px]"
        >
          暂无角色,请在下方创建你的第一个角色。
        </div>
        <div v-else class="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3">
          <button
            v-for="c in list"
            :key="c.id"
            class="text-left p-3 rounded-lg bg-gradient-to-br from-slate-800/80 to-slate-900/80 border-2 border-amber-700/30 hover:border-amber-400 hover:from-slate-700/80 transition active:scale-[0.98] shadow"
            @click="handleSelect(c.id)"
          >
            <div class="flex items-center gap-2 mb-2">
              <div
                class="w-10 h-10 rounded-md bg-gradient-to-br from-amber-500 to-rose-700 flex items-center justify-center text-xl"
              >
                ⚔️
              </div>
              <div class="flex-1 min-w-0">
                <div class="text-amber-100 text-[15px] font-bold truncate">{{ c.nickname }}</div>
                <div class="text-amber-200/50 text-[10px]">
                  Lv.{{ c.level }} · 战力 {{ c.combatPower.toLocaleString() }}
                </div>
              </div>
              <span
                v-if="c.isDev"
                class="px-1.5 py-0.5 rounded bg-rose-700 text-amber-100 text-[10px] font-bold"
              >
                DEV
              </span>
            </div>
            <div class="text-amber-200/40 text-[10px]">
              创建于 {{ new Date(c.createdAt).toLocaleDateString() }}
            </div>
          </button>
        </div>
      </section>

      <!-- 创建角色 -->
      <section class="rounded-lg border-2 border-amber-700/30 bg-black/30 p-4">
        <h2 class="text-amber-200 text-[14px] font-bold mb-3">创建新角色</h2>
        <form class="flex flex-col sm:flex-row gap-2" @submit.prevent="handleCreate">
          <input
            v-model="newNick"
            type="text"
            maxlength="12"
            placeholder="昵称(2~12 字符,中英文/数字/下划线)"
            class="flex-1 px-3 py-2 rounded bg-black/50 border border-amber-700/40 focus:border-amber-400 outline-none text-amber-100 placeholder-amber-200/30 text-[13px]"
            :disabled="creating"
          />
          <button
            type="submit"
            class="px-4 py-2 rounded bg-gradient-to-r from-amber-500 to-rose-600 text-slate-900 font-bold text-[13px] hover:brightness-110 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed transition"
            :disabled="creating || newNick.trim().length < 2"
          >
            {{ creating ? '创建中…' : '创建并进入' }}
          </button>
        </form>
        <div v-if="errorMsg" class="mt-2 text-rose-300 text-[12px]">❌ {{ errorMsg }}</div>
      </section>
    </main>
  </div>
</template>
